from dataclasses import dataclass
from typing import Literal

@dataclass
class SafetyGateResult:
    confirmed_incidents_90d: int
    open_safety_tickets: int
    adversarial_eval_passed: bool         # red-team eval with no critical failures
    bias_eval_passed: bool                # demographic parity check passed
    pii_leak_incidents_90d: int

    def is_blocked(self) -> tuple[bool, list[str]]:
        reasons = []
        if self.confirmed_incidents_90d > 0:
            reasons.append(
                f"{self.confirmed_incidents_90d} confirmed safety incident(s) in 90-day window"
            )
        if self.open_safety_tickets > 0:
            reasons.append(
                f"{self.open_safety_tickets} open safety ticket(s) — must be resolved before graduation"
            )
        if not self.adversarial_eval_passed:
            reasons.append("Adversarial (red-team) evaluation did not pass")
        if not self.bias_eval_passed:
            reasons.append("Bias evaluation did not pass demographic parity check")
        if self.pii_leak_incidents_90d > 0:
            reasons.append(
                f"{self.pii_leak_incidents_90d} PII leak incident(s) in 90-day window"
            )
        return bool(reasons), reasons

result = SafetyGateResult(
    confirmed_incidents_90d=0,
    open_safety_tickets=0,
    adversarial_eval_passed=True,
    bias_eval_passed=True,
    pii_leak_incidents_90d=0,
)
blocked, reasons = result.is_blocked()
print("Safety gate:", "BLOCKED" if blocked else "PASSED")

@dataclass
class CostGateResult:
    has_uncapped_cost_vector: bool          # any query pattern with no token ceiling
    actual_vs_forecast_pct: float           # e.g. 115.0 means 15% over forecast
    per_request_cost_usd: float
    business_case_per_request_usd: float
    token_guards_active: bool               # max_tokens enforced on all paths

    def is_blocked(self) -> tuple[bool, list[str]]:
        reasons = []
        if self.has_uncapped_cost_vector:
            reasons.append(
                "Uncapped cost vector exists — at least one code path has no max_tokens ceiling"
            )
        if self.actual_vs_forecast_pct > 120.0:
            reasons.append(
                f"Actual cost is {self.actual_vs_forecast_pct:.0f}% of forecast "
                f"(blocking threshold: 120%)"
            )
        if not self.token_guards_active:
            reasons.append("Token guard rails not active on all inference paths")
        return bool(reasons), reasons

cost_gate = CostGateResult(
    has_uncapped_cost_vector=False,
    actual_vs_forecast_pct=108.0,
    per_request_cost_usd=0.042,
    business_case_per_request_usd=0.050,
    token_guards_active=True,
)
blocked, reasons = cost_gate.is_blocked()
print("Cost gate:", "BLOCKED" if blocked else "PASSED")

import httpx
from dataclasses import dataclass, field

@dataclass
class GraduationEvaluation:
    feature_id: str
    blocking_passed: list[str] = field(default_factory=list)
    blocking_failed: list[str] = field(default_factory=list)
    important_passed: list[str] = field(default_factory=list)
    important_needs_plan: list[str] = field(default_factory=list)
    advisory_passed: list[str] = field(default_factory=list)
    advisory_noted: list[str] = field(default_factory=list)

    @property
    def can_proceed_to_vote(self) -> bool:
        return len(self.blocking_failed) == 0

    def summary(self) -> str:
        lines = [f"Graduation evaluation: {self.feature_id}"]
        lines.append(f"  Blocking: {len(self.blocking_passed)} passed, {len(self.blocking_failed)} FAILED")
        lines.append(f"  Important: {len(self.important_passed)} passed, {len(self.important_needs_plan)} need plan")
        lines.append(f"  Advisory: {len(self.advisory_passed)} passed, {len(self.advisory_noted)} noted")
        lines.append(f"  Proceed to vote: {'YES' if self.can_proceed_to_vote else 'NO — blocking failures must be resolved'}")
        return "
".join(lines)

def evaluate_graduation_criteria(
    feature_id: str,
    metrics_api: str = "https://internal.ops/metrics",
) -> GraduationEvaluation:
    eval_result = GraduationEvaluation(feature_id=feature_id)
    m = httpx.get(f"{metrics_api}/graduation/{feature_id}").json()

    # Blocking checks
    if m["safety"]["confirmed_incidents_90d"] == 0 and m["safety"]["pii_leaks_90d"] == 0:
        eval_result.blocking_passed.append("safety: 0 incidents in 90-day window")
    else:
        eval_result.blocking_failed.append(
            f"safety: {m['safety']['confirmed_incidents_90d']} incident(s)"
        )

    if m["reliability"]["slo_compliance_pct"] >= 99.5:
        eval_result.blocking_passed.append(f"reliability: SLO {m['reliability']['slo_compliance_pct']}%")
    else:
        eval_result.blocking_failed.append(
            f"reliability: SLO {m['reliability']['slo_compliance_pct']}% < 99.5% target"
        )

    if not m["cost"]["has_uncapped_vector"]:
        eval_result.blocking_passed.append("cost: no uncapped cost vector")
    else:
        eval_result.blocking_failed.append("cost: uncapped cost vector detected")

    # Important checks
    if m["quality"]["eval_score_90d"] >= 4.0:
        eval_result.important_passed.append(f"quality: eval score {m['quality']['eval_score_90d']:.2f}")
    else:
        eval_result.important_needs_plan.append(
            f"quality: eval score {m['quality']['eval_score_90d']:.2f} < 4.0 — plan required"
        )

    if m["reliability"]["on_call_hours_per_week"] < 2.0:
        eval_result.important_passed.append("reliability: on-call load within target")
    else:
        eval_result.important_needs_plan.append(
            f"reliability: on-call {m['reliability']['on_call_hours_per_week']:.1f}h/week > 2h target"
        )

    # Advisory checks
    if m["business"]["adoption_pct_of_target"] >= 80:
        eval_result.advisory_passed.append("business: adoption ≥ 80% of target")
    else:
        eval_result.advisory_noted.append(
            f"business: adoption {m['business']['adoption_pct_of_target']}% of target (< 80%)"
        )

    return eval_result
